<template>
    <div>
        <!-- 面包屑 -->
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>用户管理</el-breadcrumb-item>
            <el-breadcrumb-item>用户列表</el-breadcrumb-item>
        </el-breadcrumb>
        <!-- 卡片 -->
        <el-card class="box-card">
            <el-button type="primary">添加分类</el-button>

            <!-- <el-table :data="tableData" style="width: 100%;margin-bottom: 20px;" border row-key="cat_id"
                :tree-props="{children: 'children', hasChildren: 'hasChildren'}">
                <el-table-column type="index" label="#" sortable>
                </el-table-column>
                <el-table-column prop="cat_name" label="日期" sortable width="180">
                </el-table-column>
                <el-table-column prop="name" label="姓名" sortable width="180">
                </el-table-column>
                <el-table-column prop="address" label="地址">
                </el-table-column>
            </el-table> -->

            <el-table :data="tableData" style="width: 100%;margin-bottom: 20px;" row-key="cat_id" border
                :tree-props="{children: 'children', hasChildren: 'hasChildren'}">
                <el-table-column type="index" label="#" sortable>
                </el-table-column>
                <el-table-column prop="cat_name" label="分类名称" sortable width="180">
                </el-table-column>
                <el-table-column label="是否有效">
                    <template>
                        <i class="el-icon-circle-check"></i>
                    </template>
                </el-table-column>

                <el-table-column label="排序" sortable width="180">
                    <template slot-scope="scope">
                        <!-- {{scope.row}} -->
                        <div v-show="scope.row.cat_level==0">
                            <el-tag>一级</el-tag>
                        </div>
                        <div v-show="scope.row.cat_level==1">
                            <el-tag type="success">二级</el-tag>
                        </div>
                        <div v-show="scope.row.cat_level==2">
                            <el-tag type="warning">三级</el-tag>
                        </div>

                    </template>
                </el-table-column>
                <el-table-column label="操作" sortable width="180">
                    <template slot-scope="scope">
                        <!-- {{scope.row}} -->
                        <el-button type="primary" icon="el-icon-edit" @click="edit(scope.row)" size="mini">编辑
                        </el-button>
                        <el-button type="danger" icon="el-icon-delete" @click="open(scope.row.cat_id)" size="mini">删除
                        </el-button>
                    </template>
                </el-table-column>
            </el-table>


            <!-- 分页 -->
            <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange"
                :page-sizes="[5, 6, 7, 8]" :page-size="100" layout="total, sizes, prev, pager, next, jumper"
                :total="total">
            </el-pagination>

            <!-- 编辑框框 -->
            <el-dialog title="修改分类" :visible.sync="dialogVisible" width="30%">
                <!-- <span>这是一段信息</span> -->
                <el-form label-width="80px">
                    <el-form-item label="分类名称">
                        <el-input v-model="username.name"></el-input>
                    </el-form-item>
                </el-form>
                <span slot="footer" class="dialog-footer">
                    <el-button @click="dialogVisible = false">取 消</el-button>
                    <el-button type="primary" @click="queX()">确 定</el-button>
                </span>
            </el-dialog>


        </el-card>
    </div>
</template>

<script>
    export default {
        data() {
            return {
                type: 3,
                a: 1,
                b: 5,
                tableData: [],
                total: 0,
                dialogVisible: false,
                username: {
                    name: '',
                    id: null
                }
            };
        },
        created() {

        },
        mounted() {
            this.ajax()
        },
        methods: {
            ajax() {
                this.$http.get('/categories', {
                    params: {
                        pagenum: this.a,
                        pagesize: this.b
                    }
                }).then(res => {
                    console.log(res)
                    this.tableData = res.data.data.result
                    this.total = res.data.data.total
                })
            },
            handleSizeChange(val) {
                // console.log(`每页 ${val} 条`);
                this.b = val
                this.ajax()
            },
            handleCurrentChange(val) {
                // console.log(`当前页: ${val}`);
                this.a = val
                this.ajax()
            },
            // 点击编辑的按钮的时候
            edit(obj) {
                // console.log(obj)
                this.username.name = obj.cat_name
                this.username.id = obj.cat_id
                // console.log(this.name)
                this.dialogVisible = true
            },
            async queX() {
                let { data } = await this.$http.put('/categories/' + this.username.id, { cat_name: this.username.name })
                // console.log(data)
                if (data.meta.msg == "更新成功") {
                    this.$message({
                        type: 'success',
                        message: data.meta.msg,
                        duration: 1000
                    });
                    this.dialogVisible = false
                    this.ajax()
                }
            },
            open(i) {
                console.log(i)
                this.$confirm('此操作将永久删除该分类, 是否继续?', '提示', {
                    confirmButtonText: '确定',
                    cancelButtonText: '取消',
                    type: 'warning'
                }).then(() => {
                    this.$http.delete('/categories/' + i).then(res => {
                        console.log(res)
                        if (res.data.meta.msg == "删除成功") {
                            this.$message({
                                type: 'success',
                                message: res.data.meta.msg,
                                duration: 1000
                            });
                            this.ajax()
                        }
                    })

                })
            }
        }
    };
</script>

<style scoped>
    .box-card {
        margin-top: 10px;
    }

    .demo-table-expand {
        font-size: 0;
    }

    .demo-table-expand label {
        width: 90px;
        color: #99a9bf;
    }

    .demo-table-expand .el-form-item {
        margin-right: 0;
        margin-bottom: 0;
        width: 50%;
    }
</style>